const raw = $input.first().json;
const d = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const email = d.email || '';
const resumeUrl = d.resumeUrl || '';
const company = d.processName ? (d.processName !== 'your diagnostic' ? d.processName : '') : '';

const emailHtml = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<h1 style="margin: 0; font-size: 24px;">Your Progress Has Been Saved</h1>' +
    '<p style="margin: 8px 0 0; opacity: 0.8;">Continue your workflow diagnostic whenever you&apos;re ready</p>' +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">Hi there,</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;">You saved your workflow diagnostic progress. Click the link below to continue where you left off:</p>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + resumeUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">Continue My Diagnostic</a>' +
    '</div>' +
    '<p style="font-size: 13px; color: #94a3b8; text-align: center;">This link is valid for 30 days.</p>' +
  '</div>' +
'</div>';

return { json: { to: String(email), subject: 'Continue your Workflow Diagnostic' + (company ? ' — ' + company : ''), html: emailHtml } };
